import {describe,it,expect} from 'vitest';
import request from 'supertest';
import {app} from '../app';
import SwaggerParser from '@apidevtools/swagger-parser';
import Ajv from 'ajv';

describe('OpenAPI compliance',()=>{
  it('GET /orders matches documented schema',async()=>{
    const api=await SwaggerParser.dereference('openapi.yaml');
    const schema=(api as any).paths['/orders'].get.responses['200'].content['application/json'].schema;
    const r=await request(app).get('/orders').expect(200);
    const ajv=new Ajv();
    const validate=ajv.compile(schema);
    const ok=validate(r.body);
    if(!ok)throw new Error(`schema mismatch: ${JSON.stringify(validate.errors,null,2)}`);
  });
});

export function setTag(tags:string[],tag:string):string[]{return tags.includes(tag)?tags:[...tags,tag];}

import {describe,it} from 'vitest';
import fc from 'fast-check';
import {setTag} from './tags';

describe('setTag idempotence',()=>{
  it('repeated set is no-op',()=>{
    fc.assert(fc.property(fc.array(fc.string()),fc.string(),(initial,tag)=>{
      const once=setTag(initial,tag);
      const twice=setTag(once,tag);
      return JSON.stringify(once)===JSON.stringify(twice);
    }),{numRuns:300});
  });
});

