import {Navigate,useLocation} from 'react-router';
import {useAuth} from './auth';
export function RequireRole({role,children}:{role:'admin'|'manager';children:React.ReactNode}){
  const {user}=useAuth();
  if(!user)return <Navigate to="/login" replace/>;
  if(user.role!==role&&user.role!=='admin')return <Navigate to="/403" replace/>;
  return <>{children}</>;
}

import {describe,it,expect} from 'vitest';
import {render,screen} from '@testing-library/react';
import {createMemoryRouter,RouterProvider} from 'react-router';
import {RequireRole} from './RequireRole';
import {AuthProvider} from './auth';

function mount(role:string|null){
  const router=createMemoryRouter([
    {path:'/admin',element:<RequireRole role="admin"><div>admin</div></RequireRole>},
    {path:'/403',element:<div>forbidden</div>},
    {path:'/login',element:<div>login</div>}
  ],{initialEntries:['/admin']});
  return render(<AuthProvider value={{user:role?{id:'u1',role}:null}}><RouterProvider router={router}/></AuthProvider>);
}

describe('RequireRole',()=>{
  it('admin sees admin content',()=>{mount('admin');expect(screen.getByText('admin')).toBeInTheDocument();});
  it('member sees 403',()=>{mount('member');expect(screen.getByText('forbidden')).toBeInTheDocument();});
  it('no user sees login',()=>{mount(null);expect(screen.getByText('login')).toBeInTheDocument();});
});

