import {memo} from 'react';
import {describe,it,expect} from 'vitest';
import {render,rerender} from '@testing-library/react';

let renders=0;
const Foo=memo(function Foo({n}:{n:number}){renders++;return <div>{n}</div>;});

describe('Foo memo behavior',()=>{
  it('renders once for stable props',()=>{
    renders=0;
    const {rerender:r}=render(<Foo n={1}/>);
    r(<Foo n={1}/>);
    r(<Foo n={1}/>);
    expect(renders).toBe(1);
  });
  it('re-renders when prop changes',()=>{
    renders=0;
    const {rerender:r}=render(<Foo n={1}/>);
    r(<Foo n={2}/>);
    expect(renders).toBe(2);
  });
});

