interface Tree{value?:number;children?:Tree[]}
export function flatten(t:Tree):number[]{
  if(!t.children)return t.value!==undefined?[t.value]:[];
  return t.children.flatMap(flatten);
}
function countLeaves(t:Tree):number{return t.children?t.children.reduce((s,c)=>s+countLeaves(c),0):(t.value!==undefined?1:0);}

import {describe,it} from 'vitest';
import fc from 'fast-check';
import {flatten} from './tree';

const leafArb=fc.record({value:fc.integer()});
const treeArb=fc.letrec(tie=>({
  tree:fc.oneof({maxDepth:5},leafArb,fc.record({children:fc.array(tie('tree'),{maxLength:3})}))
})).tree;

describe('flatten preserves leaves',()=>{
  it('output length === leaf count',()=>{
    fc.assert(fc.property(treeArb,(t)=>flatten(t as any).length===countLeaves(t as any)),{numRuns:200});
  });
});

