import {describe,it,expect} from 'vitest';
import request from 'supertest';
import {app} from '../app';

describe('refresh rotation',()=>{
  it('rotates refresh token; old reuse rejected',async()=>{
    const login=await request(app).post('/auth/login').send({email:'a@b.co',password:'x'}).expect(200);
    const refreshToken=login.body.refreshToken;
    const r1=await request(app).post('/auth/refresh').send({refreshToken}).expect(200);
    expect(r1.body.refreshToken).not.toBe(refreshToken);
    // Reuse old refresh
    await request(app).post('/auth/refresh').send({refreshToken}).expect(401);
  });
});
